import { Component, inject, signal, computed, OnInit, ChangeDetectionStrategy } from '@angular/core';
import { CodeValueService, MPageService } from '@clinicaloffice/mpage-developer';
import { ConfigurationService } from '../../services/configuration.service';
import { OncSchedConfiguration } from '../../models/schedule.model';

@Component({
  selector: 'app-config',
  standalone: true,
  templateUrl: './config.html',
  styleUrl: './config.scss',
  changeDetection: ChangeDetectionStrategy.OnPush
})
export class ConfigComponent implements OnInit {
  private readonly codeValueService = inject(CodeValueService);
  private readonly configService = inject(ConfigurationService);
  private readonly mPage = inject(MPageService);

  readonly saving = signal(false);
  readonly codeSetLoaded = signal(false);
  readonly searchText = signal('');
  readonly selectedApptTypes = signal<number[]>([]);
  readonly statusMessage = signal<{ type: 'success' | 'error'; text: string } | null>(null);

  readonly allApptTypes = signal<{ codeValue: number; display: string }[]>([]);

  readonly filteredApptTypes = computed(() => {
    const search = this.searchText().toLowerCase();
    const all = this.allApptTypes();
    if (!search) return all;
    return all.filter(a => a.display.toLowerCase().includes(search));
  });

  readonly hasUnsavedChanges = computed(() => {
    const current = this.configService.configuration()?.APPOINTMENT_TYPES ?? [];
    const edited = this.selectedApptTypes();
    if (current.length !== edited.length) return true;
    return !current.every(v => edited.includes(v));
  });

  ngOnInit(): void {
    // Load code set 14230 (appointment types)
    this.codeValueService.load(14230, 0, '', '', '', false, () => {
      const codeValues = this.codeValueService.getCodeSet(14230);
      const values = codeValues.map(cv => ({ codeValue: cv.codeValue, display: cv.display }));
      values.sort((a, b) => a.display.localeCompare(b.display));
      this.allApptTypes.set(values);
      this.codeSetLoaded.set(true);
    });

    // Initialize selected from current config
    const config = this.configService.configuration();
    if (config?.APPOINTMENT_TYPES) {
      this.selectedApptTypes.set([...config.APPOINTMENT_TYPES]);
    }
  }

  checkAllFiltered(): void {
    const filteredCodes = this.filteredApptTypes().map(a => a.codeValue);
    this.selectedApptTypes.update(current => {
      const set = new Set(current);
      for (const code of filteredCodes) set.add(code);
      return [...set];
    });
  }

  uncheckAllFiltered(): void {
    const filteredCodes = new Set(this.filteredApptTypes().map(a => a.codeValue));
    this.selectedApptTypes.update(current => current.filter(v => !filteredCodes.has(v)));
  }

  toggleApptType(codeValue: number): void {
    this.selectedApptTypes.update(current => {
      if (current.includes(codeValue)) {
        return current.filter(v => v !== codeValue);
      }
      return [...current, codeValue];
    });
  }

  isSelected(codeValue: number): boolean {
    return this.selectedApptTypes().includes(codeValue);
  }

  save(): void {
    this.saving.set(true);
    const config = this.configService.configuration();
    const updated: OncSchedConfiguration = {
      ...config ?? { UPDT_DT_TM: '', APPOINTMENT_TYPES: [] },
      APPOINTMENT_TYPES: this.selectedApptTypes()
    };

    this.configService.saveConfiguration(updated);
    this.saving.set(false);
    this.statusMessage.set({ type: 'success', text: 'Configuration saved.' });
    setTimeout(() => this.statusMessage.set(null), 3000);
  }

  discard(): void {
    const config = this.configService.configuration();
    this.selectedApptTypes.set([...(config?.APPOINTMENT_TYPES ?? [])]);
    this.statusMessage.set(null);
  }

  onSearchInput(event: Event): void {
    this.searchText.set((event.target as HTMLInputElement).value);
  }
}
